const now = new Date();
const hotCutoff = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
const warmCutoff = new Date(now.getTime() - 48 * 60 * 60 * 1000).toISOString();

return [{
  json: {
    run_at: now.toISOString(),
    hot_cutoff: hotCutoff,
    warm_cutoff: warmCutoff,
    org_id: '9d6cb56d-3f21-4f7b-80ea-797a7c2c62cf',
    supabase_url: 'https://jtlnmypcrgmzxeuiffup.supabase.co',
    recipient_email: 'antonio@anclora.com',
    sender_email: 'Anclora Alerts <antonio@anclora.com>'
  }
}];

function safeItems(nodeName) {
  try {
    return $items(nodeName, 0, 0) || [];
  } catch (error) {
    return [];
  }
}

function normalize(nodeName) {
  const items = safeItems(nodeName);
  const raw = items.map((item) => item.json);

  return raw
    .flatMap((entry) => Array.isArray(entry) ? entry : [entry])
    .filter((entry) => entry && Object.keys(entry).length > 0);
}

const context = safeItems('Build SLA Query Context')[0]?.json ?? {};
const hotLeads = normalize('Fetch Hot SLA Breaches');
const warmLeads = normalize('Fetch Warm SLA Breaches');
const total = hotLeads.length + warmLeads.length;

if (total === 0) {
  return [];
}

const generatedAt = context.run_at || new Date().toISOString();
const generatedAtLocal = new Date(generatedAt).toLocaleString('es-ES', {
  dateStyle: 'short',
  timeStyle: 'medium',
});

const formatLead = (lead) => {
  const createdAt = lead.created_at ? new Date(lead.created_at).toISOString() : 'n/d';
  return `- ${lead.name || 'Lead sin nombre'} | prioridad ${lead.ai_priority || 'n/d'} | canal ${lead.source_channel || 'n/d'} | asset ${lead.source_detail || 'n/d'} | creado ${createdAt} | id ${lead.id}`;
};

const subject = `[Anclora] SLA vencido - ${hotLeads.length} hot / ${warmLeads.length} warm - ${generatedAtLocal}`;

const text = [
  'Resumen de leads sin atender dentro de SLA',
  '',
  `Generado: ${generatedAtLocal}`,
  '',
  `Hot vencidos: ${hotLeads.length}`,
  ...hotLeads.map(formatLead),
  '',
  `Warm vencidos: ${warmLeads.length}`,
  ...warmLeads.map(formatLead),
].join('\n');

const renderGroup = (title, leads, accent) => {
  if (!leads.length) {
    return `<p style="margin:0 0 16px;color:#6b7280;">${title}: sin incidencias.</p>`;
  }

  return `
    <div style="margin:0 0 20px;">
      <h2 style="margin:0 0 12px;font-size:18px;color:${accent};">${title}: ${leads.length}</h2>
      <ul style="margin:0;padding-left:18px;line-height:1.6;">
        ${leads.map((lead) => `<li><strong>${lead.name || 'Lead sin nombre'}</strong> · prioridad ${lead.ai_priority || 'n/d'} · canal ${lead.source_channel || 'n/d'} · asset ${lead.source_detail || 'n/d'} · creado ${lead.created_at || 'n/d'} · id ${lead.id}</li>`).join('')}
      </ul>
    </div>
  `;
};

const html = `
  <div style="font-family:Arial,sans-serif;line-height:1.5;color:#111827;max-width:780px;margin:0 auto;padding:24px;">
    <div style="border-radius:16px;padding:20px 24px;background:#111827;color:#f8fafc;">
      <div style="font-size:12px;letter-spacing:.18em;text-transform:uppercase;opacity:.72;">Watchdog SLA</div>
      <h1 style="margin:8px 0 0;font-size:28px;line-height:1.15;">Leads sin atender dentro de SLA</h1>
      <p style="margin:12px 0 0;font-size:15px;opacity:.88;">Hot vencidos: ${hotLeads.length} · Warm vencidos: ${warmLeads.length}</p>
    </div>
    <div style="margin-top:18px;border:1px solid #e5e7eb;border-radius:16px;padding:20px 24px;background:#ffffff;">
      ${renderGroup('Hot', hotLeads, '#b91c1c')}
      ${renderGroup('Warm', warmLeads, '#b45309')}
      <p style="margin:12px 0 0;color:#6b7280;"><strong>Generado:</strong> ${generatedAtLocal}</p>
    </div>
  </div>
`;

return [
  {
    json: {
      subject,
      text,
      html,
      total_breaches: total,
      hot_breaches: hotLeads.length,
      warm_breaches: warmLeads.length,
      run_at: generatedAt,
      recipient_email: context.recipient_email || 'antonio@anclora.com',
      sender_email: context.sender_email || 'Anclora Alerts <antonio@anclora.com>',
    }
  }
];
